<?php
namespace App\Services\Dashboard;
use App\Models\{Umkm,UmkmBusinessField,UmkmLegality,UmkmPerformanceRecord};use Illuminate\Contracts\Pagination\LengthAwarePaginator;
class DashboardAnalyticsService { private int $minAggregate=3; public function indicators(array $filters=[]): array { $q=$this->officialQuery($filters); $ids=(clone $q)->pluck('id'); return ['total_umkm_resmi'=>(clone $q)->count(),'legalitas_terisi'=>UmkmLegality::query()->whereIn('umkm_id',$ids)->whereNotNull('nib_number')->count(),'kinerja_records'=>UmkmPerformanceRecord::query()->whereIn('umkm_id',$ids)->count()]; } public function kbliComposition(array $filters=[]): array { return UmkmBusinessField::query()->selectRaw('kbli_reference_id, COUNT(*) total')->whereIn('umkm_id',$this->officialQuery($filters)->pluck('id'))->groupBy('kbli_reference_id')->havingRaw('COUNT(*) >= ?',[$this->minAggregate])->get()->toArray(); } public function legalityStatus(array $filters=[]): array { return UmkmLegality::query()->selectRaw('status_data, COUNT(*) total')->whereIn('umkm_id',$this->officialQuery($filters)->pluck('id'))->groupBy('status_data')->havingRaw('COUNT(*) >= ?',[$this->minAggregate])->get()->toArray(); } public function performanceTrend(array $filters=[]): array { return UmkmPerformanceRecord::query()->selectRaw('monitoring_period_id, AVG(monthly_revenue) avg_revenue, COUNT(*) total')->whereIn('umkm_id',$this->officialQuery($filters)->pluck('id'))->groupBy('monitoring_period_id')->havingRaw('COUNT(*) >= ?',[$this->minAggregate])->get()->toArray(); } public function mapAggregate(array $filters=[]): array { return Umkm::query()->selectRaw('status_data, COUNT(*) total')->whereIn('id',$this->officialQuery($filters)->pluck('id'))->groupBy('status_data')->havingRaw('COUNT(*) >= ?',[$this->minAggregate])->get()->toArray(); } public function summaryTable(array $filters=[], int $perPage=20): LengthAwarePaginator { return $this->officialQuery($filters)->select(['id','umkm_code','business_name','status_data','quality_status'])->paginate($perPage); } private function officialQuery(array $filters=[]) { $q=Umkm::query()->where('status_data','resmi'); if(!empty($filters['quality_status'])) $q->where('quality_status',$filters['quality_status']); return $q; }}
